parameters.inputSchema:
{
  "verdict": {
    "type": "string",
    "enum": ["YES", "NO"],
    "description": "Whether the content should be published as an article"
  },
  "article_worthy": {
    "type": "boolean",
    "description": "True if verdict is YES or MAYBE, false if NO"
  },
  "article_type": {
    "type": "string",
    "enum": ["Help Desk", "Knowledge Base", "N/A"],
    "description": "Help Desk for reactive problem-solution articles, Knowledge Base for proactive educational/reference articles"
  },
  "priority": {
    "type": "number",
    "description": "1-10 score based on how much this article would reduce inbound support volume and improve response times"
  },
  "suggested_title": {
    "type": "string",
    "description": "A clear, search-friendly title a bookkeeping client would actually type"
  },
  "target_audience": {
    "type": "string",
    "enum": ["New Clients", "All Clients", "Specific Segment"],
    "description": "Who this article is intended for"
  },
  "responsiveness_impact": {
    "type": "string",
    "enum": ["High", "Medium", "Low"],
    "description": "How much this article improves response times or reduces ticket volume"
  },
  "responsiveness_explanation": {
    "type": "string",
    "description": "One sentence explaining the responsiveness impact"
  },
  "reasoning": {
    "type": "string",
    "description": "2-3 sentences explaining the evaluation decision"
  },
  "rework_needed": {
    "type": "string",
    "description": "If verdict is MAYBE, describes what changes would make it publishable. Empty string if not applicable."
  },
  "suggested_tags": {
    "type": "array",
    "items": {
      "type": "string"
    },
    "description": "List of tags for categorizing the article"
  }
}

